mapper.select:
select rn, orderid as orderid, basedate, runcnt, jobid, version, jobname, system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, eststarttime, runningtime, realstarttime, realendtime, orderdate, orderuserid ,archive_date, delete_date ,( select upddate from cotdl.tbl_piirestore r where r.old_orderid=k.orderid and r.custid = k.custid and r.status='Ended OK') as restore_date ,custid, cust_nm, birth_dt, rsdnt_altrntv_id, cust_pin, arc_del_date, exclude_reason from ( select ROWNUM rn, a.* from ( select /*+ leading(b c a) use_hash(a) use_hash(c)*/ b.orderid, to_char(b.basedate,'yyyy/mm/dd') as basedate, b.runcnt, b.jobid, b.version, b.jobname, b.system, b.policy_id, b.keymap_id, b.jobtype, b.runtype, b.calendar, b.time, b.status, b.confirmflag, b.holdflag, b.forceokflag, b.killflag, to_char(b.eststarttime,'yyyy/mm/dd hh24:mi:ss') as eststarttime, b.runningtime, to_char(b.realstarttime,'yyyy/mm/dd hh24:mi:ss') as realstarttime, to_char(b.realendtime,'yyyy/mm/dd hh24:mi:ss') as realendtime, to_char(b.orderdate,'yyyy/mm/dd hh24:mi:ss') as orderdate, b.orderuserid ,a.archive_date, a.delete_date, a.restore_date, a.custid, a.cust_nm, a.birth_dt, a.rsdnt_altrntv_id, a.cust_pin, a.arc_del_date, exclude_reason from cotdl.tbl_piiextract a, cotdl.tbl_piiorder b, cotdl.tbl_piiorderstep c where 1 = 1 and a.orderid=b.orderid and a.archive_date is not null and a.delete_date is not null and b.status = 'Ended OK' and c.orderid=b.orderid and c.steptype = 'EXE_ARCHIVE'
order by orderid desc
) a order by orderid desc ) k where rn <= #{pagenum} * #{amount} and rn > (#{pagenum} -1) * #{amount} order by orderid desc

 
		 
		select 
			restoreid, phase, old_orderid, new_orderid, keymap_id, basedate, custid, cust_nm, birth_dt, rsdnt_altrntv_id, cust_pin, old_jobid, old_version, new_jobid, status, regdate, upddate, reguserid, upduserid
		from ( 
				select 
					 ROWNUM rn, restoreid, phase, old_orderid, new_orderid, keymap_id, basedate, custid, cust_nm, birth_dt, rsdnt_altrntv_id, cust_pin, old_jobid, old_version, new_jobid, status, regdate, upddate, reguserid, upduserid
				from (
						select restoreid, phase, old_orderid, new_orderid, keymap_id, to_char(basedate,'yyyy/mm/dd') as basedate, custid, cust_nm, birth_dt, rsdnt_altrntv_id, cust_pin, old_jobid, old_version, new_jobid, status, to_char(regdate,'yyyy/mm/dd HH24:MI:SS') as regdate, to_char(upddate,'yyyy/mm/dd HH24:MI:SS') as upddate, reguserid, upduserid
						  from cotdl.tbl_piirestore order by restoreid desc
					 ) a
				where 1=1
		
	    
		 
	    
	    
				  and  ROWNUM <= #{pagenum} * #{amount} 
				order by restoreid
			  ) k
		where rn > (#{pagenum} -1) * #{amount} 
		order by restoreid desc
